import{j as s,b as a,c as i,a9 as n}from"./chunks/framework.CFGK5tmi.js";const e="/assets/%E8%A1%A8%E7%A9%BA%E9%97%B4%E7%BB%93%E6%9E%84.drawio.D3Wb8i_t.png",p="/assets/COMPACT.drawio.DykMJ_g4.png",y=JSON.parse('{"title":"MySQL是怎样存储数据的","description":"","frontmatter":{},"headers":[],"relativePath":"backend/db/mysql/MySQL是怎样存储数据的.md","filePath":"backend/db/mysql/MySQL是怎样存储数据的.md","lastUpdated":null}'),l={name:"backend/db/mysql/MySQL是怎样存储数据的.md"},t=n(`<h1 id="mysql是怎样存储数据的" tabindex="-1">MySQL是怎样存储数据的 <a class="header-anchor" href="#mysql是怎样存储数据的" aria-label="Permalink to &quot;MySQL是怎样存储数据的&quot;">​</a></h1><p>众所周知，MySQL是一个持久化的数据库，因此它是存储在磁盘中的，而MySQL实际存储功能是交给<mark>存储引擎层</mark>的，因此，对于不同的存储引擎，其存储的实现方式也是不同的。但是InnoDB是MySQL现在的默认存储引擎，因此这里讨论InnoDB它是怎样存储数据的。</p><h2 id="存储位置" tabindex="-1">存储位置 <a class="header-anchor" href="#存储位置" aria-label="Permalink to &quot;存储位置&quot;">​</a></h2><p>首先我们需要先知道MySQL的数据文件是存在哪个文件夹下。</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;datadir&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">---------------+-----------------+</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Variable_name | </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">           |</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">---------------+-----------------+</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| datadir       | </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">var</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lib</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> |</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">---------------+-----------------+</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> row</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> in</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>我们每创建一个数据库，设其名为database，就会在<code>/var/lib/mysql/</code>目录下新增一个名为database的文件夹，这个文件夹里就存放着具体的表的数据，比如我的big_market数据库下就存放着下面的表</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>D:.</span></span>
<span class="line"><span>    award.ibd</span></span>
<span class="line"><span>    rule_tree.ibd</span></span>
<span class="line"><span>    rule_tree_node.ibd</span></span>
<span class="line"><span>    rule_tree_node_line.ibd</span></span>
<span class="line"><span>    strategy.ibd</span></span>
<span class="line"><span>    strategy_award.ibd</span></span>
<span class="line"><span>    strategy_rule.ibd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看出来，只有一种类型的文件。例如，award表的数据和表结构会存在award.ibd文件内。</p><h2 id="表空间结构" tabindex="-1">表空间结构 <a class="header-anchor" href="#表空间结构" aria-label="Permalink to &quot;表空间结构&quot;">​</a></h2><p><strong>表空间由段（segment）、区（extent）、页（page）、行（row）组成</strong>，InnoDB存储引擎的逻辑存储结构大致如下图：</p><p><img src="`+e+'" alt="img"></p><p>1、行（row） 数据库表中的记录都是按行（row）进行存放的，一条记录就对应着一个行。每行记录根据不同的行格式，有不同的存储结构。</p><p>2、页（page）记录是按行来存储的，但是数据库的读取并不以「行」为单位，否则一次读取（也就是一次 I/O 操作）只能处理一行数据，效率会非常低。实际上IO是以页为单位的。<strong>一个页的大小是16KB。</strong></p><p>3、区（extent）B+ 树中每一层都是通过双向链表连接起来的，如果是以页为单位来分配存储空间，那么链表中相邻的两个页之间的物理位置并不是连续的，可能离得非常远，那么磁盘查询时就会有大量的随机I/O，随机 I/O 是非常慢的。因此有了<strong>区</strong>的概念，表中数据量很大的时候，就直接以区为单位进行分配了，一个区大小1MB，因此连续的64页被分为一个区，这样做可以使得相邻的页物理的位置也能够相邻。</p><p>4、段（segment）</p><ul><li>索引段：存放 B + 树的非叶子节点的区的集合；</li><li>数据段：存放 B + 树的叶子节点的区的集合；</li><li>回滚段：存放的是回滚数据的区的集合</li></ul><h2 id="行格式" tabindex="-1">行格式 <a class="header-anchor" href="#行格式" aria-label="Permalink to &quot;行格式&quot;">​</a></h2><p>InnoDB 提供了 4 种行格式，分别是 Redundant、Compact、Dynamic和 Compressed 行格式。</p><h3 id="compact格式" tabindex="-1">Compact格式 <a class="header-anchor" href="#compact格式" aria-label="Permalink to &quot;Compact格式&quot;">​</a></h3><p>如下图所示，Compact格式把一个数据分为了<mark>“记录的额外信息”</mark>和<mark>“记录的真实数据”</mark>两个部分，</p><p><img src="'+p+'" alt="img"></p><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTc1NTg1NDUxNjElN0Q="></div>',22),r=[t];function h(d,k,c,o,b,m){return a(),i("div",null,r)}const E=s(l,[["render",h]]);export{y as __pageData,E as default};
